const cycle = $('Abrir janela idempotente').first().json;
const candidates = $input.all().map((item) => item.json).filter((pr) => pr && pr.draft === true && pr.base?.ref === 'main' && /^memory\/\d{4}-\d{2}-\d{2}$/.test(pr.head?.ref ?? '') && pr.head?.sha);
const candidate = candidates.length === 1 ? { number: candidates[0].number, head: candidates[0].head.sha, branch: candidates[0].head.ref, title: candidates[0].title } : null;
return [{ json: { ...cycle, candidate, candidateCount: candidates.length, incomplete: candidates.length > 1 } }];

const nextAttempt = $json.attempt + 1;
const slots = $json.slots;
return [{ json: { ...$json, attempt: nextAttempt, slot: slots[nextAttempt] ?? null, continueWindow: nextAttempt < slots.length } }];

const candidate = $('Selecionar candidato').first().json.candidate;
const marker = `<!-- sentinela-noturna:v1:head=${candidate.head} -->`;
const alreadyReviewed = $input.all().some((item) => String(item.json.body ?? '').includes(marker));
return [{ json: { ...$('Selecionar candidato').first().json, alreadyReviewed } }];

const context = $('Checar SHA revisado').first().json;
const forbidden = /(^|\/)(\.env|.*\.(sqlite|db|pem|key)|.*(backup|cookie|token|secret).*)$/i;
const files = $input.all().map((item) => ({ filename: String(item.json.filename ?? ''), status: String(item.json.status ?? ''), patch: String(item.json.patch ?? '') }));
const findings = files.filter((file) => forbidden.test(file.filename)).map((file) => ({ severity: 'blocked', category: 'security', file: file.filename, evidence: 'Caminho proibido para consolidação pública.', recommendation: 'Remova o arquivo do PR.' }));
const verdict = context.incomplete ? 'incomplete' : findings.length ? 'blocked' : 'normal';
return [{ json: { ...context, files, deterministic: { verdict, findings, passed: verdict === 'normal' } } }];

const value = $json;
const redact = (text) => String(text).replace(/-----BEGIN [A-Z ]+-----[\s\S]*?-----END [A-Z ]+-----/g, '[REDACTED]').replace(/\b(?:gh[pousr]_[A-Za-z0-9_]+|AIza[\w-]+|sk-[A-Za-z0-9_-]+)\b/g, '[REDACTED]').replace(/https?:\/\/[^\s)\]]+/gi, '[REDACTED]');
const maxBytes = 24000;
let payload = redact(JSON.stringify({ repository: value.repository, candidate: value.candidate, deterministic: value.deterministic, files: value.files }));
while (Buffer.byteLength(payload, 'utf8') > maxBytes) payload = payload.slice(0, -256);
return [{ json: { ...value, aiInput: payload, geminiCalls: 0 } }];

const context = $('Preparar pacote redigido').first().json;
const raw = $json.candidates?.[0]?.content?.parts?.[0]?.text ?? '';
let review; try { review = JSON.parse(raw); } catch { review = null; }
const verdict = ['normal', 'attention', 'blocked', 'incomplete'].includes(review?.verdict) ? review.verdict : 'incomplete';
const findings = Array.isArray(review?.findings) ? review.findings.slice(0, 20) : [];
return [{ json: { ...context, geminiCalls: 1, review: { verdict, summary: String(review?.summary ?? 'Resposta de revisão inválida.'), findings, requiresHumanReview: Boolean(review?.requiresHumanReview) || verdict !== 'normal' } }];

const deterministic = $json.deterministic;
const review = $json.review ?? { verdict: deterministic.verdict, summary: 'Bloqueio determinístico.', findings: deterministic.findings, requiresHumanReview: true };
const verdict = deterministic.verdict === 'blocked' ? 'blocked' : review.verdict;
const label = verdict === 'normal' ? 'sentinela:revisado' : verdict === 'attention' ? 'sentinela:atencao' : verdict === 'blocked' ? 'sentinela:bloqueado' : null;
const marker = `<!-- sentinela-noturna:v1:head=${$json.candidate.head} -->`;
const findings = (review.findings ?? []).map((item) => `- ${item.file ?? 'contexto'}: ${item.evidence ?? item.recommendation ?? 'revisar'}`).join('
') || '- Nenhum achado adicional.';
const body = `Sentinela noturna — resultado

Head: ${$json.candidate.head}
Verificações determinísticas: ${deterministic.verdict}
Gemini: ${$json.geminiCalls ? 'acionado' : 'não acionado'}
Groq: ${$json.groqUsed ? 'acionado' : 'não acionado'}
Veredicto: ${verdict}

${review.summary}

Achados:
${findings}

${marker}`;
return [{ json: { ...$json, final: { verdict, label, body, marker } } }];
